#!/usr/bin/env node
// ─────────────────────────────────────────────────────────────────────
// No-raw-invoke guard.
//
// Every Tauri command has a typed binding in `src/lib/bindings.ts`
// (generated by tauri-specta: `commands.createBlock(...)`, etc.). App
// code MUST call commands through those typed bindings — which carry
// the argument/return types and the `AppError` result shape — instead
// of the stringly-typed `invoke('snake_case_command', …)` bypass.
//
// A raw `invoke('some_command')` sidesteps the type system entirely: a
// renamed command, a changed argument name, or a wrong payload shape
// compiles clean and only fails at runtime. This guard forbids the
// pattern in app code so the typed layer is the single IPC seam.
//
// ─── Detection ──────────────────────────────────────────────────────
//
// Flags any `invoke('cmd', …)` or `invoke<T>('cmd', …)` whose first
// argument is a string literal beginning with a lowercase letter (the
// shape of every Tauri command name). Comments are stripped before
// scanning, so a commented-out or documented `invoke('list_blocks')`
// is not a violation. Calls that pass a variable (not a string
// literal) — e.g. the low-level `internals.invoke(cmd, args)` inside
// the observability patch — are not matched.
//
// ─── Scope / exemptions ─────────────────────────────────────────────
//
// Scans `src/**/*.{ts,tsx}`, excluding test files (`*.test.ts[x]`,
// `__tests__/`, `/tests/`). The following are the sanctioned
// raw-invoke sites and are exempt:
//
//   - `src/lib/bindings.ts`        generated typed-binding layer (uses
//                                  the aliased `__TAURI_INVOKE`).
//   - `src/lib/tauri.ts`           the hand-written wrapper layer that
//   - `src/lib/tauri/`             the bindings migration funnels
//                                  through (`unwrap(await commands.*)`);
//                                  split into per-domain modules in #2902.
//   - `src/lib/observability/`     the invoke-instrumentation seam that
//                                  patches `__TAURI_INTERNALS__.invoke`.
//   - `src/lib/tauri-mock.ts` /    the e2e / dev IPC mock that stands in
//     `src/lib/tauri-mock/`        for the Rust backend.
//
// Usage: node scripts/check-raw-invoke.mjs
//        node scripts/check-raw-invoke.mjs --self-test
// Exit:  0 = clean, 1 = at least one violation, 2 = repo layout /
//        self-test failure.
// ─────────────────────────────────────────────────────────────────────

import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'

const ROOT = path.resolve(import.meta.dirname, '..')
const SRC_DIR = path.join(ROOT, 'src')

// Repo-relative (POSIX) exact-file and directory-prefix exemptions.
// Directory prefixes end with `/`.
const EXEMPT_FILES = Object.freeze(
  new Set(['src/lib/bindings.ts', 'src/lib/tauri.ts', 'src/lib/tauri-mock.ts']),
)
const EXEMPT_DIR_PREFIXES = Object.freeze([
  'src/lib/observability/',
  'src/lib/tauri-mock/',
  'src/lib/tauri/',
])

// `invoke(` or `invoke<T>(` followed by a string literal whose first
// char is a lowercase letter (a Tauri command name).
const RAW_INVOKE_RE = /\binvoke\s*(?:<[^>]*>)?\(\s*(['"`])([a-z][A-Za-z0-9_]*)\1/g

// ─── helpers ────────────────────────────────────────────────────────

function toPosix(p) {
  return p.split(path.sep).join('/')
}

/**
 * Walk `src/**` for `*.ts` / `*.tsx` files, excluding test files and
 * `__tests__/` + `tests/` directories (mocked `invoke` calls in tests
 * are legitimate and out of scope).
 */
function listSourceFiles(srcDir = SRC_DIR) {
  const out = []
  const visit = (dir) => {
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      const full = path.join(dir, entry.name)
      if (entry.isDirectory()) {
        if (entry.name === '__tests__' || entry.name === 'tests') continue
        visit(full)
      } else if (
        entry.isFile() &&
        (entry.name.endsWith('.ts') || entry.name.endsWith('.tsx')) &&
        !entry.name.endsWith('.test.ts') &&
        !entry.name.endsWith('.test.tsx') &&
        !entry.name.endsWith('.d.ts')
      ) {
        out.push(full)
      }
    }
  }
  visit(srcDir)
  return out
}

function isExempt(rel) {
  if (EXEMPT_FILES.has(rel)) return true
  return EXEMPT_DIR_PREFIXES.some((prefix) => rel.startsWith(prefix))
}

/**
 * Replace block comments (`/* … *\/`, incl. JSDoc) and line comments
 * (`// …`) with spaces so a documented/commented-out `invoke('…')` is
 * not flagged. Newlines inside block comments are preserved so line
 * numbers stay accurate for reporting.
 */
function stripComments(src) {
  let out = src.replace(/\/\*[\s\S]*?\*\//g, (m) => m.replace(/[^\n]/g, ' '))
  out = out.replace(/\/\/[^\n]*/g, (m) => ' '.repeat(m.length))
  return out
}

/**
 * Return the raw-invoke violations in a single source string as an
 * array of `{ line, command }`.
 */
function scanSource(src) {
  const stripped = stripComments(src)
  const violations = []
  for (const match of stripped.matchAll(RAW_INVOKE_RE)) {
    const upto = stripped.slice(0, match.index)
    const line = upto.split('\n').length
    violations.push({ line, command: match[2] })
  }
  return violations
}

// ─── analysis ───────────────────────────────────────────────────────

/**
 * Analyze all source files under `srcDir` for raw-invoke violations,
 * honoring the exemption list. Pure over the filesystem so the
 * self-test can drive it against a synthetic tree. Returns
 * `{ violations, scanned }`.
 */
function analyze({ root, srcDir }) {
  const violations = []
  let scanned = 0
  for (const file of listSourceFiles(srcDir)) {
    const rel = toPosix(path.relative(root, file))
    if (isExempt(rel)) continue
    scanned += 1
    const src = fs.readFileSync(file, 'utf8')
    for (const v of scanSource(src)) {
      violations.push({ file: rel, line: v.line, command: v.command })
    }
  }
  return { violations, scanned }
}

// ─── main ───────────────────────────────────────────────────────────

if (process.argv.includes('--self-test')) {
  runSelfTest()
} else {
  runGuard()
}

function runGuard() {
  if (!fs.existsSync(SRC_DIR)) {
    console.error(`ERROR: expected directory not found (repo layout changed?): ${SRC_DIR}`)
    process.exit(2)
  }

  const { violations, scanned } = analyze({ root: ROOT, srcDir: SRC_DIR })

  if (violations.length > 0) {
    console.error('ERROR: raw Tauri invoke() calls found in app code:')
    for (const v of violations) {
      console.error(`  ${v.file}:${v.line}  invoke('${v.command}', …)`)
    }
    console.error('')
    console.error('Call the typed binding from `src/lib/bindings.ts` instead of raw invoke().')
    console.error('Every command has a `commands.<camelCase>()` binding that carries the')
    console.error('argument/return types and the AppError result shape. Unwrap it with the')
    console.error('`unwrap` helper from `@/lib/tauri`, matching the other call sites:')
    console.error('')
    console.error("    import { commands } from '@/lib/bindings'")
    console.error("    import { unwrap } from '@/lib/tauri'")
    console.error('    unwrap(await commands.mcpSetEnabled(enabled))')
    console.error('')
    console.error('If a raw invoke is genuinely required (a new low-level seam), add the file')
    console.error('to the exemption list in scripts/check-raw-invoke.mjs with a justification.')
    process.exit(1)
  }

  console.log(`OK: ${scanned} source file(s) scanned, no raw invoke() calls in app code`)
}

// ─── self-test ──────────────────────────────────────────────────────
//
// Drives analyze() against a synthetic src tree so the guard's exit
// behavior is itself verified: a raw invoke FAILS, a typed-binding call
// PASSES, a commented invoke PASSES, an exempt-file raw invoke PASSES,
// and a test file is ignored.
function runSelfTest() {
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'raw-invoke-selftest-'))
  const failures = []
  const ok = (name) => console.log(`  ok   - ${name}`)
  const fail = (name, detail) => {
    failures.push(name)
    console.error(`  FAIL - ${name}: ${detail}`)
  }

  try {
    const srcDir = path.join(tmp, 'src')
    const libDir = path.join(srcDir, 'lib')
    const obsDir = path.join(libDir, 'observability')
    const compDir = path.join(srcDir, 'components')
    const testDir = path.join(compDir, '__tests__')
    for (const d of [libDir, obsDir, compDir, testDir]) fs.mkdirSync(d, { recursive: true })

    // 1. Raw invoke in a component → violation.
    fs.writeFileSync(
      path.join(compDir, 'Bad.tsx'),
      "import { invoke } from '@tauri-apps/api/core'\nexport const C = () => invoke('mcp_set_enabled', { enabled: true })\n",
    )
    // 2. Raw generic invoke<T>('cmd') → violation.
    fs.writeFileSync(
      path.join(compDir, 'BadGeneric.tsx'),
      "export const C = () => invoke<Foo>('get_mcp_status')\n",
    )
    // 3. Typed-binding call → clean.
    fs.writeFileSync(
      path.join(compDir, 'Good.tsx'),
      "import { commands } from '@/lib/bindings'\nexport const C = () => unwrap(await commands.mcpSetEnabled(true))\n",
    )
    // 4. Commented / documented invoke → clean.
    fs.writeFileSync(
      path.join(compDir, 'Commented.tsx'),
      "// legacy: invoke('list_blocks') handshake was dropped\n/** JSDoc: invoke('get_mcp_status') */\nexport const C = () => null\n",
    )
    // 5. Exempt file (bindings.ts) with raw invoke → clean.
    fs.writeFileSync(
      path.join(libDir, 'bindings.ts'),
      "export const commands = { f: () => invoke('create_block') }\n",
    )
    // 6. Exempt dir (observability) with raw invoke → clean.
    fs.writeFileSync(
      path.join(obsDir, 'invoke.ts'),
      "export const f = () => invoke('some_command')\n",
    )
    // 7. Test file with raw invoke → ignored (out of scope).
    fs.writeFileSync(
      path.join(testDir, 'Bad.test.tsx'),
      "it('x', () => invoke('mcp_set_enabled'))\n",
    )

    const { violations } = analyze({ root: tmp, srcDir })
    const hit = (f) => violations.some((v) => v.file === `src/${f}`)

    if (hit('components/Bad.tsx')) ok('raw invoke in component is flagged')
    else fail('raw invoke in component is flagged', JSON.stringify(violations))

    if (hit('components/BadGeneric.tsx')) ok('raw invoke<T>() is flagged')
    else fail('raw invoke<T>() is flagged', JSON.stringify(violations))

    if (!hit('components/Good.tsx')) ok('typed-binding call passes')
    else fail('typed-binding call passes', 'Good.tsx was flagged')

    if (!hit('components/Commented.tsx')) ok('commented invoke passes')
    else fail('commented invoke passes', 'Commented.tsx was flagged')

    if (!hit('lib/bindings.ts')) ok('exempt file passes')
    else fail('exempt file passes', 'bindings.ts was flagged')

    if (!hit('lib/observability/invoke.ts')) ok('exempt dir passes')
    else fail('exempt dir passes', 'observability/invoke.ts was flagged')

    if (!violations.some((v) => v.file.includes('__tests__'))) ok('test file is ignored')
    else fail('test file is ignored', 'a __tests__ file was flagged')
  } finally {
    fs.rmSync(tmp, { recursive: true, force: true })
  }

  if (failures.length > 0) {
    console.error(`\nself-test: ${failures.length} assertion(s) failed`)
    process.exit(2)
  }
  console.log('self-test: all assertions passed')
}
